{
  "domain_analysis": {
    "business_context": "A global logistics platform adding real-time driver earnings transparency across three jurisdictions with fundamentally different labor law frameworks, driver classifications, and regulatory approval processes. The feature must display base pay, per-delivery bonus, tips, and deductions — but what each of those terms MEANS, what MUST be shown, and what CAN be shown varies by jurisdiction. This is not a single feature — it is three jurisdiction-specific implementations behind a unified concept.",
    "bounded_context": "Driver Compensation / Earnings Visibility",
    "ubiquitous_language": [
      { "term": "Earnings Breakdown", "definition": "A structured, itemized view of a driver's compensation for a given period, decomposed into base pay, per-delivery bonus, tips, and deductions." },
      { "term": "Base Pay", "definition": "The fixed compensation component. For CA employees, this is hourly wage (must meet minimum wage). For ID contractors, this is per-task base rate. For DE, this is contractual salary/hourly rate." },
      { "term": "Per-Delivery Bonus", "definition": "Variable compensation tied to individual delivery completions — e.g., surge pricing, distance bonuses, or volume incentives." },
      { "term": "Tips", "definition": "Gratuities from customers passed through to drivers. In CA, tips cannot be counted toward minimum wage. In all jurisdictions, tips must be shown as a distinct line item, never commingled with base pay." },
      { "term": "Deductions", "definition": "Amounts subtracted from gross earnings. For CA employees: taxes, benefits, legally mandated withholdings. For ID contractors: platform fees, equipment charges. For DE employees: taxes, social contributions, and any collectively agreed deductions." },
      { "term": "Driver Classification", "definition": "The legal employment status of a driver — employee (CA under AB5, DE) or independent contractor (ID) — which determines applicable labor law, tax treatment, and transparency obligations." },
      { "term": "Works Council (Betriebsrat)", "definition": "A legally mandated employee representation body in Germany with co-determination rights. Must formally approve changes to systems that display or affect compensation before deployment." },
      { "term": "Real Time", "definition": "Earnings data updated and visible to the driver within the current pay period, reflecting completed deliveries. Does NOT mean sub-second latency — means 'current and not delayed until pay day'." },
      { "term": "Wage Transparency", "definition": "Legal requirement (CA) or business policy (ID) to make compensation components visible to the earner. Scope and enforceability differ by jurisdiction." },
      { "term": "Jurisdiction", "definition": "The legal territory governing a driver's employment relationship — determines classification, required disclosures, deduction rules, and approval processes." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Every earnings breakdown MUST include all four components: base pay, per-delivery bonus, tips, and deductions — displayed as separate, clearly labeled line items. No component may be hidden or merged into another.",
      "invariant": true,
      "invariant_justification": "Commingling components (e.g., folding tips into base pay) corrupts the data model and violates the fundamental purpose of the feature. In CA, merging tips into base pay is illegal. The structural separation is a data integrity constraint.",
      "testable_assertion": "For any earnings breakdown record, exactly four top-level components exist: base_pay, per_delivery_bonus, tips, deductions — each with an independent non-null monetary value."
    },
    {
      "id": "BR-2",
      "rule": "In California, tips MUST NOT be counted toward satisfying minimum wage obligations. Base pay alone must meet or exceed the applicable minimum wage for hours worked.",
      "invariant": true,
      "invariant_justification": "California Labor Code § 351 prohibits employers from using tips as a credit toward minimum wage. Violating this creates legal liability and is not a policy choice — it is a statutory constraint on the data model.",
      "testable_assertion": "For any CA driver's pay period, assert: base_pay / hours_worked >= california_minimum_wage, independent of tips earned."
    },
    {
      "id": "BR-3",
      "rule": "In Germany, the earnings transparency feature MUST NOT be deployed to drivers until formal Betriebsrat (works council) approval is obtained and recorded in the system.",
      "invariant": true,
      "invariant_justification": "Under the Betriebsrätegesetz (Works Constitution Act), deploying a compensation display system without works council approval is a violation of co-determination rights. This is a hard legal gate — not a preference. Deploying without approval exposes the company to injunctions and fines.",
      "testable_assertion": "The feature flag for DE earnings transparency cannot be set to 'enabled' unless a works_council_approval record exists with status 'approved' and a date on or before the activation date."
    },
    {
      "id": "BR-4",
      "rule": "Deductions displayed MUST be itemized, not shown as a single lump sum. Each deduction must include a category label (e.g., 'income tax', 'platform fee', 'social insurance') and amount.",
      "invariant": true,
      "invariant_justification": "A lump-sum deduction violates transparency — the driver cannot verify correctness. In CA, employers must provide itemized wage statements (Labor Code § 226). Aggregated deductions make the 'transparency' feature meaningless and legally non-compliant in at least one jurisdiction.",
      "testable_assertion": "For any earnings breakdown, the deductions component contains one or more sub-items, each with a non-empty category string and a monetary amount. A single undifferentiated deductions total without sub-items is invalid."
    },
    {
      "id": "BR-5",
      "rule": "Earnings data must be jurisdiction-aware: the system must apply the correct driver classification (employee vs. contractor) and corresponding display rules based on the driver's operating jurisdiction.",
      "invariant": true,
      "invariant_justification": "Applying contractor rules to a CA employee (or vice versa) creates legal exposure and incorrect earnings calculations. The junction between jurisdiction and classification is a data integrity constraint — getting it wrong corrupts every downstream calculation.",
      "testable_assertion": "For any driver, the earnings breakdown engine resolves classification from the driver's jurisdiction. CA drivers are classified as employees. ID drivers are classified as contractors. DE drivers are classified as employees. No manual override of classification is permitted at the feature level."
    },
    {
      "id": "BR-6",
      "rule": "For California employee-drivers, the earnings breakdown must include a reference to total hours worked in the period, enabling the driver to independently verify hourly rate compliance.",
      "invariant": false,
      "invariant_justification": "While CA law requires accurate wage statements, the specific display of hours on the earnings breakdown screen (vs. a separate pay stub) is a UX/policy decision. The underlying data must exist, but its presentation is flexible.",
      "testable_assertion": "For CA drivers, the earnings breakdown response includes a hours_worked field with a positive numeric value for the relevant pay period."
    },
    {
      "id": "BR-7",
      "rule": "For Indonesian contractor-drivers, deductions may include platform service fees. These must be clearly labeled as platform fees and shown as a percentage and absolute amount.",
      "invariant": false,
      "invariant_justification": "The requirement to show percentage alongside absolute amount is a business policy for transparency, not a legal mandate in Indonesia. A VP could decide to show only the absolute amount.",
      "testable_assertion": "For ID drivers, any deduction with category 'platform_fee' includes both a percentage_rate and an absolute_amount field."
    },
    {
      "id": "BR-8",
      "rule": "Earnings data must be available to the driver within the current pay period — not delayed until payout. 'Real time' means updated after each completed delivery, within a reasonable processing window.",
      "invariant": false,
      "invariant_justification": "The latency SLA (e.g., within 5 minutes vs. 30 minutes of delivery completion) is a business policy, not a physical or legal constraint. The principle of within-period visibility is important but the exact timing is tunable.",
      "testable_assertion": "After a delivery is marked 'completed', the driver's earnings breakdown reflects the delivery's contribution within 30 minutes."
    },
    {
      "id": "BR-9",
      "rule": "Currency and locale formatting must match the driver's jurisdiction. CA earnings in USD, DE earnings in EUR, ID earnings in IDR. Amounts must respect local decimal/thousands separator conventions.",
      "invariant": true,
      "invariant_justification": "Displaying earnings in the wrong currency is a data corruption issue — a driver seeing EUR when they earn IDR cannot interpret their earnings. This is not a formatting preference; it is a correctness constraint.",
      "testable_assertion": "For any earnings breakdown, all monetary fields use the ISO 4217 currency code matching the driver's jurisdiction (CA=USD, DE=EUR, ID=IDR) and locale-appropriate formatting."
    },
    {
      "id": "BR-10",
      "rule": "The system must maintain an audit trail of every earnings breakdown displayed to a driver, including the timestamp, components shown, and jurisdiction rules applied.",
      "invariant": true,
      "invariant_justification": "In CA, wage statement disputes have a statutory lookback period. Without an audit trail, the platform cannot defend against claims of non-disclosure. The audit log is essential for legal defensibility in regulated jurisdictions.",
      "testable_assertion": "Every earnings breakdown view event creates an immutable audit record containing: driver_id, timestamp, jurisdiction, classification, and the full breakdown payload."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver in California completes a delivery",
      "when": "They view their earnings breakdown",
      "then": "They see base pay (meeting or exceeding minimum wage for hours worked), per-delivery bonus, tips (as a separate line), and itemized deductions (taxes, withholdings) — all in USD, with hours worked displayed"
    },
    {
      "id": "AC-2",
      "given": "The Betriebsrat in Germany has NOT approved the earnings transparency feature",
      "when": "A German driver attempts to access the earnings breakdown",
      "then": "The feature is unavailable; the driver sees a message indicating the feature is pending approval — NOT an error, and NOT the earnings data"
    },
    {
      "id": "AC-3",
      "given": "The Betriebsrat in Germany HAS approved the feature and approval is recorded",
      "when": "A German driver views their earnings breakdown",
      "then": "They see base pay, per-delivery bonus, tips, and itemized deductions (including social contributions) in EUR with locale-appropriate formatting"
    },
    {
      "id": "AC-4",
      "given": "An Indonesian contractor-driver completes a delivery",
      "when": "They view their earnings breakdown",
      "then": "They see base task rate, per-delivery bonus, tips, and itemized deductions including platform fees (shown as percentage and absolute amount) in IDR"
    },
    {
      "id": "AC-5",
      "given": "A California driver has earned tips during a pay period",
      "when": "The system calculates minimum wage compliance",
      "then": "Tips are excluded from the minimum wage calculation; only base pay is used to determine compliance"
    },
    {
      "id": "AC-6",
      "given": "A driver in any jurisdiction completes a delivery",
      "when": "30 minutes have elapsed since delivery completion",
      "then": "The earnings breakdown reflects the new delivery's compensation components"
    },
    {
      "id": "AC-7",
      "given": "A driver views their earnings breakdown in any jurisdiction",
      "when": "The breakdown is rendered",
      "then": "An immutable audit record is created with driver_id, timestamp, jurisdiction, classification, and the full breakdown payload"
    },
    {
      "id": "AC-8",
      "given": "A driver operates in California",
      "when": "The system resolves their classification",
      "then": "The driver is classified as an employee under AB5 rules; contractor classification is not available for CA drivers in this system"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A driver relocates from Indonesia to California mid-pay-period",
      "expected_behavior": "Earnings before the jurisdiction change are calculated under ID contractor rules; earnings after are calculated under CA employee rules. The breakdown must show both segments with clear jurisdiction labeling. Classification switches at the point of jurisdiction change — no retroactive reclassification."
    },
    {
      "scenario": "Betriebsrat approval is revoked or suspended after initial rollout in Germany",
      "expected_behavior": "The feature must be immediately disabled for all DE drivers. The system must support approval revocation as a state transition, not just initial approval. Historical data remains in audit logs but is no longer actively displayed."
    },
    {
      "scenario": "A California driver works a shift with zero deliveries but is on-platform and clocked in",
      "expected_behavior": "Base pay for hours worked must still be shown (they are employees). Per-delivery bonus and tips show as zero. The breakdown still renders — an empty shift is not the same as 'no data'."
    },
    {
      "scenario": "A tip is adjusted (e.g., customer changes tip after delivery) after the driver has already viewed their breakdown",
      "expected_behavior": "The next breakdown view reflects the updated tip amount. The audit trail preserves both the original and updated views. If the tip decreases, the driver sees the adjusted amount with a clear indication it was modified."
    },
    {
      "scenario": "Platform fees for Indonesian drivers change mid-pay-period",
      "expected_behavior": "Deliveries completed before the fee change use the old rate; deliveries after use the new rate. Both rates appear in the deductions itemization. Fees are never retroactively applied to already-completed deliveries."
    },
    {
      "scenario": "German minimum wage (Mindestlohn) increases during a pay period",
      "expected_behavior": "Hours worked after the effective date of the increase must reflect the new minimum. The system must track effective dates for wage floors per jurisdiction, not just current values."
    },
    {
      "scenario": "System outage prevents real-time earnings update for several hours",
      "expected_behavior": "When the system recovers, all pending earnings are backfilled and the audit trail notes the delay. The driver must never see stale data presented as current — if data is delayed, the UI must indicate the last-updated timestamp."
    },
    {
      "scenario": "A California driver's deductions exceed their gross earnings for a period (negative net pay)",
      "expected_behavior": "The breakdown must still display accurately — negative net pay is shown, not hidden. Certain deductions (e.g., tax withholding) cannot drive net pay below zero in some contexts; the system must enforce deduction ordering and caps per jurisdiction rules."
    }
  ],

  "business_impact": {
    "financial": "High exposure in California: failure to comply with AB5, minimum wage, or itemized wage statement requirements (Labor Code § 226) exposes the company to class-action lawsuits with statutory penalties of $50-$100 per pay period per employee, uncapped in aggregate. In Germany, deploying without Betriebsrat approval risks injunctions halting the feature entirely and regulatory fines. In Indonesia, financial risk is lower but incorrect fee transparency could drive driver churn on a price-sensitive market.",
    "operational": "Significant complexity: this is effectively three jurisdiction-specific feature variants that must be maintained in parallel. Each requires its own classification rules, deduction logic, compliance checks, and locale handling. The Betriebsrat approval gate introduces a non-engineering dependency that blocks the DE rollout timeline. Ongoing operational burden includes tracking wage floor changes, tax rate updates, and fee schedule changes across three jurisdictions.",
    "user": "Drivers gain trust and agency through earnings visibility — this is a major driver satisfaction and retention lever. However, if the breakdown is inaccurate or confusing, it will erode trust faster than having no transparency at all. In Indonesia, where transparency is not legally required, this is a competitive differentiator. In California, it is table stakes.",
    "risk": "CRITICAL legal risk in California if tips are commingled with base pay or minimum wage is miscalculated. HIGH legal risk in Germany if deployed without Betriebsrat sign-off. MEDIUM business risk globally if 'real time' promise is not met and drivers see stale or inconsistent data. Data privacy risk in all jurisdictions — earnings data is sensitive; access controls and audit logging are compliance-critical.",
    "stakeholders_affected": [
      { "group": "Drivers (CA)", "impact": "Gain legally mandated pay transparency. Errors directly create wage theft liability." },
      { "group": "Drivers (DE)", "impact": "Feature blocked until Betriebsrat approves. Rollout delay is expected and must be communicated." },
      { "group": "Drivers (ID)", "impact": "Gain voluntary transparency — competitive advantage for retention. Platform fee visibility may surface pricing dissatisfaction." },
      { "group": "Betriebsrat (DE)", "impact": "Must be formally consulted and must approve. They may request modifications to what is displayed — this is their legal right." },
      { "group": "Legal / Compliance Team", "impact": "Must validate jurisdiction-specific rules before each market launch. Ongoing obligation to update rules as laws change." },
      { "group": "Finance / Payroll", "impact": "Must ensure the earnings engine feeding this feature is the same source of truth as actual payroll — discrepancies between displayed and paid amounts create disputes and legal exposure." },
      { "group": "Product / Engineering", "impact": "Must build jurisdiction-aware feature flagging, classification resolution, locale handling, and audit logging. Non-trivial architecture." },
      { "group": "Customers", "impact": "Indirect: tip transparency may affect tipping behavior if drivers share breakdown screenshots publicly." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec is vague on several critical dimensions: (1) it does not acknowledge the Betriebsrat approval requirement, which is a hard legal blocker for Germany — omitting this suggests incomplete requirements gathering; (2) it does not specify driver classification per jurisdiction, which fundamentally changes what 'deductions' means; (3) 'real time' is undefined — the difference between sub-minute and end-of-day is architecturally significant; (4) no mention of audit requirements despite operating in a regulated labor market; (5) the spec treats this as one feature when it is legally three. The regulatory complexity and multiple missing-context items justify a confidence level at or below 55.",
    "high_confidence_areas": [
      "The four-component earnings breakdown structure (base, bonus, tips, deductions) is well-defined",
      "California AB5 classification and tip-separation rules are well-established law",
      "German Betriebsrat co-determination rights are unambiguous — approval IS required",
      "Currency and locale rules per jurisdiction are straightforward"
    ],
    "low_confidence_areas": [
      "The spec does not define 'real time' — the latency SLA is a guess",
      "Deduction categories per jurisdiction are not specified — I inferred standard categories",
      "Whether the Betriebsrat will require modifications to the display format is unknown until consultation occurs",
      "How driver jurisdiction is determined for edge cases (relocation, cross-border) is unspecified",
      "Indonesian regulatory landscape for gig worker transparency is less well-documented — local legal review needed",
      "Data retention and privacy requirements for the audit trail are not specified"
    ],
    "assumptions": [
      "Driver classification is determined by operating jurisdiction, not nationality or contract origin",
      "The platform already has a payroll/earnings engine — this feature is a read-only view layer on top of existing data",
      "Betriebsrat consultation has not yet begun for Germany",
      "30-minute update latency is acceptable for 'real time' — this is an assumption, not a confirmed requirement",
      "The audit trail requirement is inferred from CA Labor Code § 226, not explicitly stated in the spec"
    ]
  },

  "escalations": [
    {
      "type": "missing_context",
      "description": "The spec does not acknowledge the German Betriebsrat approval requirement. This is a hard legal prerequisite — the feature CANNOT ship in Germany without it. The implementation must include a gating mechanism, and the project plan must include a non-engineering workstream for works council consultation. Has this consultation been initiated? What is the expected timeline?",
      "affected_stakeholders": ["Drivers (DE)", "Betriebsrat (DE)", "Legal / Compliance Team", "Product / Engineering"],
      "options": [
        "A) Block DE rollout entirely until Betriebsrat approval is obtained; ship CA and ID first",
        "B) Begin Betriebsrat consultation immediately in parallel with engineering; build feature flag to gate DE",
        "C) Build the feature globally but disable for DE with no timeline commitment"
      ],
      "recommendation": "Option B — begin consultation NOW. Betriebsrat processes can take weeks to months. Engineering should build jurisdiction-gated feature flags regardless. Delaying the conversation only delays the DE launch."
    },
    {
      "type": "ambiguity",
      "description": "'Real time' is undefined in the spec. In a logistics context, this could mean anything from sub-second websocket updates to 'visible within the current pay period.' The architecture, infrastructure cost, and driver expectations differ enormously. The spec must define an explicit update latency SLA.",
      "affected_stakeholders": ["Drivers (all jurisdictions)", "Product / Engineering"],
      "options": [
        "A) After each delivery completion, update within 5 minutes (near-real-time, event-driven)",
        "B) Batch update every 30 minutes during active shifts",
        "C) Update once daily at end of shift"
      ],
      "recommendation": "Option A — event-driven update within 5 minutes of delivery completion. This matches driver mental models ('I just finished a delivery, let me check my earnings') and is technically achievable with standard event architectures. Daily updates would undermine the 'transparency' promise."
    },
    {
      "type": "missing_context",
      "description": "The spec does not address how deductions differ by driver classification. Employee deductions (CA, DE) include mandatory tax withholding, social insurance, and benefits — these are employer obligations. Contractor deductions (ID) include platform fees and potentially self-employment tax estimates. Treating these identically in the data model would be a domain error. What deduction categories should be supported per jurisdiction?",
      "affected_stakeholders": ["Finance / Payroll", "Legal / Compliance Team", "Drivers (all jurisdictions)"],
      "options": [
        "A) Define a fixed set of deduction categories per jurisdiction upfront",
        "B) Use a flexible category model but enforce jurisdiction-specific validation rules",
        "C) Defer deduction itemization and show only gross-to-net for v1"
      ],
      "recommendation": "Option B — flexible categories with jurisdiction validation. Labor laws change; hardcoding categories is brittle. But validation must ensure CA always shows legally required items (federal tax, state tax, SDI, etc.)."
    },
    {
      "type": "missing_context",
      "description": "No mention of data privacy or access controls. Earnings data is sensitive personal information protected under GDPR (Germany), CCPA (California), and Indonesian data protection law. Who besides the driver can see the breakdown? Can support agents access it? Is it stored, and for how long? These are not optional considerations — GDPR violations carry fines up to 4% of global revenue.",
      "affected_stakeholders": ["Drivers (all jurisdictions)", "Legal / Compliance Team", "Engineering"],
      "options": [
        "A) Restrict access to the driver only; support agents see redacted view",
        "B) Full access for driver and authorized support agents with audit logging",
        "C) Defer privacy design to a separate workstream"
      ],
      "recommendation": "Option B — driver has full access, support agents have audited access with data minimization. But this MUST be reviewed by legal before implementation begins. Do not defer — privacy-by-design is a GDPR requirement."
    }
  ],

  "rejection_reasons": []
}

